47	/*
48	 * This function creates a dtype object when the object is a ctypes subclass.
49	 *
50	 * Returns `Py_NotImplemented` if the type is not a ctypes subclass.
51	 */
52	static PyArray_Descr *
53	_try_convert_from_ctypes_type(PyTypeObject *type)
54	{
55	    PyObject *_numpy_dtype_ctypes;
56	    PyObject *res;
57	
58	    if (!npy_ctypes_check(type)) {
59	        Py_INCREF(Py_NotImplemented);
60	        return (PyArray_Descr *)Py_NotImplemented;
61	    }
62	
63	    /* Call the python function of the same name. */
64	    _numpy_dtype_ctypes = PyImport_ImportModule("numpy._core._dtype_ctypes");
65	    if (_numpy_dtype_ctypes == NULL) {
66	        return NULL;
67	    }
68	    res = PyObject_CallMethod(_numpy_dtype_ctypes, "dtype_from_ctypes_type", "O", (PyObject *)type);
69	    Py_DECREF(_numpy_dtype_ctypes);
70	    if (res == NULL) {
71	        return NULL;
72	    }
73	
74	    /*
75	     * sanity check that dtype_from_ctypes_type returned the right type,
76	     * since getting it wrong would give segfaults.
77	     */
78	    if (!PyObject_TypeCheck(res, &PyArrayDescr_Type)) {
79	        Py_DECREF(res);
80	        PyErr_BadInternalCall();
81	        return NULL;
82	    }
83	
84	    return (PyArray_Descr *)res;
85	}
