87	/*
88	 * This function creates a dtype object when the object has a "__numpy_dtype__"
89	 * or "dtype" attribute which must be valid NumPy dtype instance.
90	 *
91	 * Returns `Py_NotImplemented` if this is not possible.
92	 */
93	static PyArray_Descr *
94	_try_convert_from_dtype_attr(PyObject *obj)
95	{
96	    int used_dtype_attr = 0;
97	    /* For arbitrary objects that have a "dtype" attribute */
98	    PyObject *attr;
99	    int res = PyObject_GetOptionalAttr(obj, npy_interned_str.numpy_dtype, &attr);
100	    if (res < 0) {
101	        return NULL;
102	    }
103	    else if (res == 0) {
104	        /*
105	         * When "__numpy_dtype__" does not exist, also check "dtype". This should
106	         * be removed in the future.
107	         * We do however support a weird `class myclass(np.void): dtype = ...`
108	         * syntax.
109	         */
110	        used_dtype_attr = 1;
111	        int res = PyObject_GetOptionalAttr(obj, npy_interned_str.dtype, &attr);
112	        if (res < 0) {
113	            return NULL;
114	        }
115	        else if (res == 0) {
116	            Py_INCREF(Py_NotImplemented);
117	            return (PyArray_Descr *)Py_NotImplemented;
118	        }
119	    }
120	    if (!PyArray_DescrCheck(attr)) {
121	        if (PyType_Check(obj) && PyObject_HasAttrString(attr, "__get__")) {
122	            /* If the object has a __get__, assume this is a class property. */
123	            Py_DECREF(attr);
124	            Py_INCREF(Py_NotImplemented);
125	            return (PyArray_Descr *)Py_NotImplemented;
126	        }
127	        PyErr_Format(PyExc_ValueError,
128	            "Could not convert %R to a NumPy dtype (via `.%S` value %R).", obj,
129	            used_dtype_attr ? npy_interned_str.dtype : npy_interned_str.numpy_dtype,
130	            attr);
131	        Py_DECREF(attr);
132	        return NULL;
133	    }
134	    /* The dtype attribute is already a valid descriptor */
135	    return (PyArray_Descr *)attr;
136	}
