53	/* Fast string 'class' */
54	typedef struct {
55	    char *s;
56	    size_t allocated;
57	    size_t pos;
58	} _tmp_string_t;
59	
60	#define INIT_SIZE   16
61	
62	static int
63	_append_char(_tmp_string_t *s, char c)
64	{
65	    if (s->pos >= s->allocated) {
66	        char *p;
67	        size_t to_alloc = (s->allocated == 0) ? INIT_SIZE : (2 * s->allocated);
68	
69	        p = PyMem_Realloc(s->s, to_alloc);
70	        if (p == NULL) {
71	            PyErr_SetString(PyExc_MemoryError, "memory allocation failed");
72	            return -1;
73	        }
74	        s->s = p;
75	        s->allocated = to_alloc;
76	    }
77	    s->s[s->pos] = c;
78	    ++s->pos;
79	    return 0;
80	}
