82	static int
83	_append_str(_tmp_string_t *s, char const *p)
84	{
85	    for (; *p != '\0'; p++) {
86	        if (_append_char(s, *p) < 0) {
87	            return -1;
88	        }
89	    }
90	    return 0;
91	}
