69	/*
70	 * Forwards a method call to a Python function while adding `self`:
71	 * callable(self, ...)
72	 */
73	static PyObject *
74	npy_forward_method(
75	        PyObject *callable, PyObject *self,
76	        PyObject *const *args, Py_ssize_t len_args, PyObject *kwnames)
77	{
78	    /*
79	     * `PY_VECTORCALL_ARGUMENTS_OFFSET` seems never set, probably `args[-1]`
80	     * is always `self` but do not rely on it unless Python documents that.
81	     */
82	    npy_intp len_kwargs = kwnames != NULL ? PyTuple_GET_SIZE(kwnames) : 0;
83	    npy_intp total_nargs = (len_args + len_kwargs);
84	
85	    NPY_ALLOC_WORKSPACE(new_args, PyObject *, 14, total_nargs + 1);
86	    if (new_args == NULL) {
87	        /*
88	         * This may fail if Python starts passing `PY_VECTORCALL_ARGUMENTS_OFFSET`
89	         * and we should probably add a fast-path for that (hopefully almost)
90	         * always taken.
91	         */
92	        return NULL;
93	    }
94	
95	    new_args[0] = self;
96	    memcpy(&new_args[1], args, total_nargs * sizeof(PyObject *));
97	    PyObject *res = PyObject_Vectorcall(callable, new_args, len_args+1, kwnames);
98	
99	    npy_free_workspace(new_args);
100	    return res;
101	}
