56	NPY_NO_EXPORT int
57	array_shape_set_internal(PyArrayObject *self, PyObject *val)
58	{
59	    int nd;
60	    PyArrayObject *ret;
61	    assert(val);
62	
63	    /* Assumes C-order */
64	    ret = (PyArrayObject *)PyArray_Reshape(self, val);
65	    if (ret == NULL) {
66	        return -1;
67	    }
68	    if (PyArray_DATA(ret) != PyArray_DATA(self)) {
69	        Py_DECREF(ret);
70	        PyErr_SetString(PyExc_AttributeError,
71	                        "Incompatible shape for in-place modification. Use "
72	                        "`.reshape()` to make a copy with the desired shape.");
73	        return -1;
74	    }
75	
76	    nd = PyArray_NDIM(ret);
77	    if (nd > 0) {
78	        /* create new dimensions and strides */
79	        npy_intp *_dimensions = npy_alloc_cache_dim(2 * nd);
80	        if (_dimensions == NULL) {
81	            Py_DECREF(ret);
82	            PyErr_NoMemory();
83	            return -1;
84	        }
85	        /* Free old dimensions and strides */
86	        npy_free_cache_dim_array(self);
87	        ((PyArrayObject_fields *)self)->nd = nd;
88	        ((PyArrayObject_fields *)self)->dimensions = _dimensions;
89	        ((PyArrayObject_fields *)self)->strides = _dimensions + nd;
90	
91	        if (nd) {
92	            memcpy(PyArray_DIMS(self), PyArray_DIMS(ret), nd*sizeof(npy_intp));
93	            memcpy(PyArray_STRIDES(self), PyArray_STRIDES(ret), nd*sizeof(npy_intp));
94	        }
95	    }
96	    else {
97	        /* Free old dimensions and strides */
98	        npy_free_cache_dim_array(self);
99	        ((PyArrayObject_fields *)self)->nd = 0;
100	        ((PyArrayObject_fields *)self)->dimensions = NULL;
101	        ((PyArrayObject_fields *)self)->strides = NULL;
102	    }
103	
104	    Py_DECREF(ret);
105	    PyArray_UpdateFlags(self, NPY_ARRAY_C_CONTIGUOUS | NPY_ARRAY_F_CONTIGUOUS);
